// ==================== MAIN ====================
const SETS = [
  { name: '1. Substation Fundamentals', description: 'Substation mission, types (AIS vs GIS, transmission vs distribution), voltage hierarchy, major equipment, control house, station service, and DC battery systems.', cards: set1 },
  { name: '2. Power Transformers', description: 'Voltage transformation, ratings, cooling methods (ONAN/ONAF/OFAF/ODAF), tap changers, impedance, winding configurations, losses, BIL, and nameplate data.', cards: set2 },
  { name: '3. Circuit Breakers & Switching', description: 'Circuit breaker types (SF6, oil, air blast, vacuum), operating mechanisms, circuit switchers, disconnect switches, interlocking, earth switches, reclosers, and sectionalizers.', cards: set3 },
  { name: '4. Bus Configurations', description: 'Single bus, double bus, ring bus, breaker-and-a-half, double bus double breaker, main-tie-main, bus materials, and bus differential protection.', cards: set4 },
  { name: '5. Protection & Instrument Transformers', description: 'CTs, PTs, CCVTs, protective relay functions (50/51/21/67/87), relay coordination, neutral grounding resistors, fuses, digital fault recorders, SCADA/RTU, lockout relays, and breaker failure protection.', cards: set5 },
  { name: '6. Surge Protection & Grounding', description: 'Metal-oxide surge arresters, installation locations, BIL coordination, ground grid design (IEEE 80), system grounding methods, and shield wires.', cards: set6 },
  { name: '7. MV Switchgear to 480V Panels', description: 'Metal-clad MV switchgear, step-down transformers, 480Y/277V systems, LV switchgear vs switchboards, panelboards, MCCs, power factor correction, arc flash, and one-line diagrams.', cards: set7 },
];

async function main() {
  console.log('Creating topic...');
  const topic = await post('/api/topics', {
    name: 'Electrical Substations & Distribution',
    description: 'Power delivery from transmission lines through substations, transformers, MV switchgear, and distribution down to 480V panels. Equipment, protection, bus configurations, and voltage hierarchy.',
    color: '#ea580c',
    icon: 'book'
  });
  const topicId = topic.id;
  console.log(`  Topic created: ${topicId}`);

  let totalCards = 0;

  for (const s of SETS) {
    console.log(`\nCreating set: ${s.name}`);
    const set = await post(`/api/topics/${topicId}/sets`, { name: s.name, description: s.description });
    const setId = set.id;
    console.log(`  Set created: ${setId} (${s.cards.length} cards)`);

    for (let i = 0; i < s.cards.length; i++) {
      const c = s.cards[i];
      await post(`/api/sets/${setId}/cards`, c);
      totalCards++;
      process.stdout.write(`  Card ${i + 1}/${s.cards.length}\r`);
    }
    console.log(`  ✓ ${s.cards.length} cards created`);
  }

  console.log(`\nDone! Created ${SETS.length} sets with ${totalCards} total cards.`);
}

main().catch(err => { console.error('FATAL:', err); process.exit(1); });
